public Map<Integer, List<LinkAndLoadSettingAction>> parseLinkAndLoadActions(String lnlActs) throws JSONException {
    Map<Integer, List<LinkAndLoadSettingAction>> actions = new HashMap<>();
    if(lnlActs == null || lnlActs.trim().isEmpty()) return actions;
    try {
    	JSONArray actionArray = new JSONArray(lnlActs);
        for(int i = 0; i < actionArray.length(); i++) {
            JSONObject actionJSON = actionArray.getJSONObject(i);
            String type = actionJSON.getString("action");
            int domainId = actionJSON.getInt("domainId");
            int linkedRootDomainId = actionJSON.getInt("s");
            int linkedDomainId = actionJSON.getInt("stf");
            String linkedFormMvp = actionJSON.getString("mvp");
            
            LinkAndLoadSettingAction action = LinkAndLoadActionFactory.getInstance(type);
            action.setDomainId(domainId);
            action.setLinkedRootDomainId(linkedRootDomainId);
            action.setLinkedDomainId(linkedDomainId);
            action.setLinkedFormMvpString(linkedFormMvp);
            
            List<LinkAndLoadSettingAction> domainIdActionList = actions.get(domainId);
            if(domainIdActionList == null) {
                domainIdActionList = new ArrayList<>();
                actions.put(domainId, domainIdActionList);
            }
            domainIdActionList.add(action);
        }
    } catch(Exception e) {
        System.out.println("Parse lnlActs failed: " + e.getMessage());
        e.printStackTrace();
    }
    return actions;
}

public void setSourceLinkedFieldUnique(String apname, Map<Integer, List<LinkAndLoadSettingAction>> lnlActs, HttpSession session) {
    if (lnlActs.size() == 0) return;
    Set<String> paths = new HashSet<>();
    try {
        for (Map.Entry<Integer, List<LinkAndLoadSettingAction>> entry : lnlActs.entrySet()) {
            List<LinkAndLoadSettingAction> actions = entry.getValue();
            LinkAndLoadSetting domainIdSetting = new LinkAndLoadSetting();
            //when runs until the last action, we get the last and only domainIdSetting
            //the last action is the newest action
            for (LinkAndLoadSettingAction action : actions) {
                domainIdSetting = action.execute(domainIdSetting);
            }
            
            int linkedDomainId = domainIdSetting.getLinkedDomainId();
            String mvpString = domainIdSetting.getLinkedFormMvpString();
            String[] sec = mvpString.split("\\|");
            if (sec.length < 2) continue;
            String path = sec[0], fn = sec[1];
            
            NUIForm sourceForm = AppManager.getFormPage(apname, path, fn);
            CellInfo linkedField = sourceForm.getField(linkedDomainId);
            if (linkedField == null) continue;
            linkedField.setAttribute("noDup", "true");
            sourceForm.saveFile(apname, path);
            
            NUIForm sourceListingPage = AppManager.getListingPage(apname, path, fn);
            linkedField = sourceListingPage.getField(linkedDomainId);
            if (linkedField == null) continue;
            linkedField.setAttribute("noDup", "true");
            sourceListingPage.saveFile(apname, path);
            
            paths.add(path);
        }
    } catch(Exception ignored) {}
    
    if (paths.size() > 0) {
        for (String path : paths) {
            //sync with builder mode
            NUIFormSetInfo.resetForms(apname, path, session);
        }
    }
}

